import { useMemo, useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "What is half-life?", a: "Half-life is the time it takes for half of a substance to decay or transform. After one half-life, 50% remains; after two half-lives, 25% remains; after three, 12.5% remains." },
  { q: "What is the half-life formula?", a: "The standard half-life formula is N(t) = N0 x (1/2)^(t/t1/2), where N0 is the starting quantity, N(t) is the remaining quantity, t is elapsed time, and t1/2 is the half-life." },
  { q: "How do you calculate remaining quantity after decay?", a: "Divide elapsed time by the half-life to find the number of half-life periods, then multiply the starting quantity by one-half raised to that power." },
  { q: "What elements have the shortest half-lives?", a: "Some highly unstable synthetic isotopes have extremely short half-lives measured in fractions of a second. Half-life length depends on the isotope, not just the element name." },
  { q: "How is half-life used in carbon dating?", a: "Carbon dating compares the remaining carbon-14 in organic material to its original amount. Because carbon-14 decays at a known half-life, scientists can estimate age from the remaining fraction." },
];

type Mode = "remaining" | "time" | "halfLife";

const fmt = (value: number) => Number.isFinite(value) ? Number(value.toFixed(6)).toLocaleString() : "Invalid";

export default function HalfLifeCalculator() {
  const [mode, setMode] = useState<Mode>("remaining");
  const [initial, setInitial] = useState(100);
  const [remaining, setRemaining] = useState(25);
  const [time, setTime] = useState(10);
  const [halfLife, setHalfLife] = useState(5);
  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

  const result = useMemo(() => {
    if (initial <= 0) return { label: "Invalid input", value: "Initial quantity must be greater than zero.", step: "Enter a positive starting quantity." };
    if (mode === "remaining") {
      if (halfLife <= 0) return { label: "Invalid input", value: "Half-life must be greater than zero.", step: "Use a positive half-life." };
      const value = initial * Math.pow(0.5, time / halfLife);
      return { label: "Remaining Quantity", value: fmt(value), step: `N(t) = ${initial} x (1/2)^(${time}/${halfLife}) = ${fmt(value)}` };
    }
    if (mode === "time") {
      if (remaining <= 0 || remaining >= initial || halfLife <= 0) return { label: "Invalid input", value: "Remaining must be between 0 and the initial quantity.", step: "Use 0 < remaining < initial and a positive half-life." };
      const value = halfLife * Math.log(remaining / initial) / Math.log(0.5);
      return { label: "Elapsed Time", value: fmt(value), step: `t = ${halfLife} x log(${remaining}/${initial}) / log(1/2) = ${fmt(value)}` };
    }
    if (remaining <= 0 || remaining >= initial || time <= 0) return { label: "Invalid input", value: "Use 0 < remaining < initial and positive time.", step: "Half-life can be found only when quantity decreases over positive time." };
    const value = time * Math.log(0.5) / Math.log(remaining / initial);
    return { label: "Half-Life", value: fmt(value), step: `t1/2 = ${time} x log(1/2) / log(${remaining}/${initial}) = ${fmt(value)}` };
  }, [mode, initial, remaining, time, halfLife]);

  return (
    <>
      <SEOHead title="Free Half-Life Calculator Online - Calculate Radioactive Decay Instantly | CalcHive" description="Free online half-life calculator. Calculate remaining quantity after radioactive decay, time elapsed or half-life from measurements instantly. 100% free for chemistry and physics students, no signup required." canonical="/half-life-calculator" keywords="free half life calculator, radioactive decay calculator free online, half life formula calculator free, nuclear decay calculator free, chemistry half life calculator free" category="Science Calculators" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Science</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Half-Life Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Use this radioactive decay calculator free online to calculate remaining quantity, elapsed time, or half-life from measurements.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="mb-6"><label htmlFor="mode" className="text-sm font-semibold text-foreground block mb-2">Mode</label><select id="mode" value={mode} onChange={(event) => setMode(event.target.value as Mode)} className={inputClass}><option value="remaining">Calculate remaining quantity</option><option value="time">Calculate elapsed time</option><option value="halfLife">Calculate half-life</option></select></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            <div><label htmlFor="initial" className="text-sm font-semibold text-foreground block mb-2">Initial quantity</label><input id="initial" type="number" inputMode="decimal" value={initial} onChange={(event) => setInitial(Number(event.target.value))} className={inputClass} /></div>
            {mode !== "remaining" && <div><label htmlFor="remaining" className="text-sm font-semibold text-foreground block mb-2">Remaining quantity</label><input id="remaining" type="number" inputMode="decimal" value={remaining} onChange={(event) => setRemaining(Number(event.target.value))} className={inputClass} /></div>}
            {mode !== "halfLife" && <div><label htmlFor="half-life" className="text-sm font-semibold text-foreground block mb-2">Half-life</label><input id="half-life" type="number" inputMode="decimal" value={halfLife} onChange={(event) => setHalfLife(Number(event.target.value))} className={inputClass} /></div>}
            {mode !== "time" && <div><label htmlFor="time" className="text-sm font-semibold text-foreground block mb-2">Elapsed time</label><input id="time" type="number" inputMode="decimal" value={time} onChange={(event) => setTime(Number(event.target.value))} className={inputClass} /></div>}
          </div>
          <motion.div key={`${mode}-${initial}-${remaining}-${time}-${halfLife}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">{result.label}</p><p className="text-5xl font-black text-white tracking-tight break-words" data-testid="result-half-life">{result.value}</p></div>
            <div className="mt-4 bg-accent/60 border border-border rounded-xl p-4"><p className="text-xs font-bold uppercase tracking-wide text-muted-foreground mb-2">Step by step</p><p className="text-sm text-foreground" data-testid="result-steps">{result.step}</p></div>
          </motion.div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Half-Life and Radioactive Decay for Free</h2><p className="text-muted-foreground leading-relaxed">Choose what you need to solve, enter the known measurements, and this half life formula calculator free tool applies the decay equation instantly.</p>
          <h2 className="text-2xl font-bold text-foreground">How the Half-Life Formula N(t) = N0 x (1/2)^(t/t1/2) Works</h2><p className="text-muted-foreground leading-relaxed">The formula reduces the starting amount by one-half for each half-life period that passes, which is why decay curves become smaller over time.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Radioactive Decay Calculator for Chemistry and Physics Students</h2><p className="text-muted-foreground leading-relaxed">Use this nuclear decay calculator free for homework, lab checks, and chemistry half life calculator free practice.</p>
        </section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/half-life-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


